ku_gt <- ku |> 
  dplyr::select(Date, Location, Winner, Result, Type, Order) |> 
  cbbplotR::gt_cbb_teams(Winner, Winner, include_name = FALSE) |> 
  dplyr::mutate(
    Type = dplyr::if_else(Type == "NCAA Final", "trophy",
                          Type)) |>
  dplyr::arrange(Order) |> 
  gt::gt() |> 
  gt::cols_hide(Order) |> 
  gtUtils::gt_theme_gtutils() |> 
  gt::fmt_markdown(Winner) |>
  gt::fmt_icon(
   columns = c(Type),
   rows = c(2, 13),
    fill_color = "orange"
 ) |> 
  gtExtras::gt_merge_stack(
    col1 = "Date",
    col2 = "Location",
    palette = c("black", "#848484"),
    small_cap = FALSE
  ) |> 
  gtExtras::gt_add_divider(columns = c(Location),
                           sides = "right",
                           color = "black") |>
  gt::cols_align(columns = c(Date, Location, Result),
                 align = "left") |> 
  gt::tab_header(title = gt::html("<span style='color:#56a0d3'>North Carolina</span> and <span style='color:#E8000D'>Kansas</span> Series History"),
                 subtitle = gt::html("The two teams have met seven times in the NCAA Tournament and 13 times overall since the 1957 season. Kansas leads the overall series 7-6.<br>
                                     Kansas plays its first game in Chapel Hill, NC this Friday.")) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data from Stathead and sports-reference.com, theme via {gtUtils}<hr>
        <b>Table by Chris at Bless your chart</b>"
      )
  ) |>
  gt::cols_align(Type, align = "left") |> 
  gt::cols_label(
    Date = "",
    Winner = "",
    Result = "",
    Type =""
  ) |> 
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(10.5),
      weight = 250
    )
  ) |>
  gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative")
